package com.keyloop.scheduler.integration;
import com.keyloop.scheduler.support.*; import org.junit.jupiter.api.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.dao.DataIntegrityViolationException; import org.springframework.jdbc.core.JdbcTemplate; import java.time.Instant; import java.util.UUID; import static org.assertj.core.api.Assertions.*;
class AppointmentExclusionConstraintIT extends PostgresIntegrationTest {@Autowired JdbcTemplate jdbc;@BeforeEach void seed(){SchedulingFixtures.reset(jdbc);insert(UUID.randomUUID(),"2030-01-01T10:00:00Z","2030-01-01T11:00:00Z","CONFIRMED");}
 @Test void rejectsOverlapAndAcceptsBackToBack(){assertThatThrownBy(()->insert(UUID.randomUUID(),"2030-01-01T10:30:00Z","2030-01-01T11:30:00Z","CONFIRMED")).isInstanceOf(DataIntegrityViolationException.class);assertThatCode(()->insert(UUID.randomUUID(),"2030-01-01T11:00:00Z","2030-01-01T12:00:00Z","CONFIRMED")).doesNotThrowAnyException();}
 private void insert(UUID id,String start,String end,String status){jdbc.update("insert into appointment(id,customer_id,vehicle_id,dealership_id,service_type_id,technician_id,service_bay_id,start_time,end_time,status,created_at) values (?,?,?,?,?,?,?,?,?,?,now())",id,SchedulingFixtures.CUSTOMER,SchedulingFixtures.VEHICLE,SchedulingFixtures.DEALERSHIP,SchedulingFixtures.SERVICE,SchedulingFixtures.TECHNICIAN,SchedulingFixtures.BAY,java.sql.Timestamp.from(Instant.parse(start)),java.sql.Timestamp.from(Instant.parse(end)),status);}
}
